import type { Api, Model } from "@earendil-works/pi-ai/compat";
import type { ExtensionContext } from "@earendil-works/pi-coding-agent";
import type { PiAutocommitConfig } from "./config.js";

// тФАтФА Port тФАтФА
export type CommitCompleteFn = (
  model: Model<Api>,
  opts: {
    systemPrompt: string;
    messages: { role: "user"; content: string; timestamp: number }[];
  },
) => Promise<{ content: Array<{ type: "string"; text?: string }> }>;

export interface CommitGroup {
  message: string;
  files: string[];
}

// тФАтФА Entry point 1: checkpointя╝ИцЬАща╗ callerя╝ЙтФАтФА
//    raw цЭРцЦЩя╝Иdiff + nameStatusя╝ЙуВТц╕буБЩуБауБСуАВcontent ч╡ДуБ┐члЛуБжуБп module хЖЕщГиуАВ
export async function generateCheckpointMessage(
  ctx: ExtensionContext,
  config: PiAutocommitConfig,
  diff: string,
  nameStatus: string,
  complete?: CommitCompleteFn,
): Promise<string>;

// тФАтФА Entry point 2: reorganiser тФАтФА
//    diff + reasoning цЦЗхнЧхИЧуВТц╕буБЩуАВextractAssistantContext уБп organizer хБ┤уБлцоЛуВЛуАВ
export async function generateReorganisedCommits(
  ctx: ExtensionContext,
  config: PiAutocommitConfig,
  diff: string,
  reasoning: string,
  complete?: CommitCompleteFn,
): Promise<CommitGroup[]>;
