import type { PiAutocommitConfig } from "./config.js";

// тФАтФА Port тФАтФА
export type CommitCompleteFn = (
  model: Model<Api>,
  opts: {
    systemPrompt: string;
    messages: { role: "user"; content: string; timestamp: number }[];
  },
) => Promise<{ content: Array<{ type: "string"; text?: string }> }>;

